import React, { useEffect, useState } from 'react';

type Page = 'upload' | 'exam' | 'result';

type Question = {
  id: number;
  question: string;
  options: string[];
  correct: number;
};

type Answers = Record<number, number>;

type Score = {
  total: number;
  correct: number;
  wrong: number;
  unattempted: number;
};

const questions: Question[] = [
  {
    id: 1,
    question: 'What is HTTP?',
    options: ['Protocol', 'Language', 'Browser', 'Operating System'],
    correct: 0,
  },
  {
    id: 2,
    question: 'What is React?',
    options: ['Library', 'Database', 'OS', 'Compiler'],
    correct: 0,
  },
  {
    id: 3,
    question: 'Which tag is used for headings in HTML?',
    options: ['<div>', '<head>', '<h1>', '<body>'],
    correct: 2,
  },
];

const calculateScore = (answers: Answers): Score => {
  let correct = 0;
  let wrong = 0;
  questions.forEach((q, index) => {
    const selected = answers[index];
    if (selected === undefined) return;
    if (selected === q.correct) correct += 1;
    else wrong += 1;
  });

  const total = correct * 4 - wrong * 1;
  return {
    total,
    correct,
    wrong,
    unattempted: questions.length - correct - wrong,
  };
};

function App() {
  const [page, setPage] = useState<Page>('upload');
  const [file, setFile] = useState<File | null>(null);
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState<Answers>({});
  const [time, setTime] = useState(300);
  const [score, setScore] = useState<Score | null>(null);

  useEffect(() => {
    if (page !== 'exam') return;
    if (time <= 0) {
      setScore(calculateScore(answers));
      setPage('result');
      return;
    }

    const timer = window.setInterval(() => {
      setTime((prev) => prev - 1);
    }, 1000);

    return () => window.clearInterval(timer);
  }, [page, time, answers]);

  const handleOption = (index: number) => {
    setAnswers((prev) => ({ ...prev, [current]: index }));
  };

  const handleSubmit = () => {
    setScore(calculateScore(answers));
    setPage('result');
  };

  return (
    <div className="min-h-screen bg-gray-100 p-6">
      {page === 'upload' && (
        <UploadPage setPage={setPage} setFile={setFile} file={file} />
      )}

      {page === 'exam' && (
        <CBTExamUI
          current={current}
          setCurrent={setCurrent}
          answers={answers}
          handleOption={handleOption}
          handleSubmit={handleSubmit}
          time={time}
          setPage={setPage}
        />
      )}

      {page === 'result' && (
        <ResultPage
          score={score}
          answers={answers}
          setPage={setPage}
          setCurrent={setCurrent}
          setAnswers={setAnswers}
          setTime={setTime}
        />
      )}
    </div>
  );
}

function UploadPage({
  setPage,
  setFile,
  file,
}: {
  setPage: React.Dispatch<React.SetStateAction<Page>>;
  setFile: React.Dispatch<React.SetStateAction<File | null>>;
  file: File | null;
}) {
  return (
    <div className="max-w-xl mx-auto bg-white p-6 rounded-2xl shadow-lg text-center">
      <h1 className="text-2xl font-bold mb-4">Upload PDF</h1>
      <input
        type="file"
        accept="application/pdf"
        onChange={(e) => setFile(e.target.files?.[0] ?? null)}
        className="mb-4 w-full text-sm text-slate-700"
      />
      {file && <p className="mb-4 text-sm text-slate-600">Selected file: {file.name}</p>}
      <button
        type="button"
        onClick={() => setPage('exam')}
        className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
      >
        Start Test
      </button>
    </div>
  );
}

function CBTExamUI({
  current,
  setCurrent,
  answers,
  handleOption,
  handleSubmit,
  time,
  setPage,
}: {
  current: number;
  setCurrent: React.Dispatch<React.SetStateAction<number>>;
  answers: Answers;
  handleOption: (index: number) => void;
  handleSubmit: () => void;
  time: number;
  setPage: React.Dispatch<React.SetStateAction<Page>>;
}) {
  return (
    <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-lg p-6">
      <div className="flex justify-between mb-4">
        <h1 className="font-bold text-xl">CBT Exam</h1>
        <span className="text-red-500">{time}s</span>
      </div>

      <h2 className="mb-4 text-lg font-semibold">
        Q{current + 1}. {questions[current].question}
      </h2>

      <div className="space-y-3">
        {questions[current].options.map((opt, i) => (
          <button
            key={i}
            type="button"
            onClick={() => handleOption(i)}
            className={`block w-full p-3 mb-2 border rounded-xl text-left transition ${
              answers[current] === i
                ? 'bg-blue-500 text-white border-blue-500'
                : 'bg-gray-50 border-gray-200 hover:border-gray-400'
            }`}
          >
            {opt}
          </button>
        ))}
      </div>

      <div className="flex justify-between mt-6">
        <button
          type="button"
          disabled={current === 0}
          onClick={() => setCurrent(current - 1)}
          className="px-4 py-2 bg-gray-300 rounded-lg disabled:opacity-50"
        >
          Previous
        </button>

        {current === questions.length - 1 ? (
          <button
            type="button"
            onClick={handleSubmit}
            className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600"
          >
            Submit
          </button>
        ) : (
          <button
            type="button"
            onClick={() => setCurrent(current + 1)}
            className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
          >
            Next
          </button>
        )}
      </div>

      <div className="grid grid-cols-5 gap-2 mt-6">
        {questions.map((_, i) => (
          <button
            key={i}
            type="button"
            onClick={() => setCurrent(i)}
            className={`p-2 rounded-lg text-sm font-semibold ${
              answers[i] !== undefined ? 'bg-green-400 text-slate-900' : 'bg-gray-300 text-slate-700'
            } ${i === current ? 'ring-2 ring-slate-700' : ''}`}
          >
            {i + 1}
          </button>
        ))}
      </div>
    </div>
  );
}

function ResultPage({
  score,
  answers,
  setPage,
  setCurrent,
  setAnswers,
  setTime,
}: {
  score: Score | null;
  answers: Answers;
  setPage: React.Dispatch<React.SetStateAction<Page>>;
  setCurrent: React.Dispatch<React.SetStateAction<number>>;
  setAnswers: React.Dispatch<React.SetStateAction<Answers>>;
  setTime: React.Dispatch<React.SetStateAction<number>>;
}) {
  const correct = score?.correct ?? 0;
  const wrong = score?.wrong ?? 0;
  const unattempted = score?.unattempted ?? questions.length;

  const reset = () => {
    setAnswers({});
    setCurrent(0);
    setTime(300);
    setPage('upload');
  };

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-lg p-6">
      <h1 className="text-2xl font-bold mb-4">Test Result</h1>
      <div className="grid gap-4 sm:grid-cols-3 mb-6">
        <div className="rounded-2xl bg-slate-50 p-4 text-center">
          <p className="text-sm text-slate-500">Score</p>
          <p className="mt-2 text-3xl font-semibold text-slate-900">{score?.total ?? 0}</p>
        </div>
        <div className="rounded-2xl bg-slate-50 p-4 text-center">
          <p className="text-sm text-slate-500">Correct</p>
          <p className="mt-2 text-3xl font-semibold text-emerald-600">{correct}</p>
        </div>
        <div className="rounded-2xl bg-slate-50 p-4 text-center">
          <p className="text-sm text-slate-500">Incorrect</p>
          <p className="mt-2 text-3xl font-semibold text-rose-600">{wrong}</p>
        </div>
      </div>

      <div className="rounded-2xl bg-slate-50 p-4 mb-6">
        <p className="text-sm text-slate-500">Unattempted</p>
        <p className="mt-2 text-xl font-semibold text-slate-900">{unattempted}</p>
      </div>

      <button
        type="button"
        onClick={reset}
        className="px-4 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-700"
      >
        Start New Test
      </button>
    </div>
  );
}

export default App;
